import networkx as nx

def greedy_chromatic_number(graph):
    coloring = {}
    for node in graph.nodes():
        available_colors = set(range(len(graph.nodes())))
        for neighbor in graph.neighbors(node):
            if neighbor in coloring:
                available_colors.discard(coloring[neighbor])
        if not available_colors:
            return None  # Graph is not colorable with this method
        coloring[node] = min(available_colors)
    return max(coloring.values()) + 1

# Example usage:
G = nx.complete_graph(3)  # Triangle graph
print(greedy_chromatic_number(G))  # Output: 3

This greedy algorithm assigns the smallest available color to each node, ensuring no adjacent nodes share the same color. While not optimal, it provides an upper bound for the classical chromatic number.
